export const CalculateRoiBody = zod.object({
  yacht_id: zod
    .string()
    .nullish()
    .describe(
      "ID of a saved My-Yacht profile to pull passport\/dimensions from. Provide EITHER yacht_id OR yacht_snapshot. My-Yacht profiles are read-only here; ROI never writes back to them.",
    ),
  yacht_snapshot: zod
    .union([
      zod
        .object({
          name: zod.string().nullish(),
          brand: zod.string().nullish(),
          model: zod.string().nullish(),
          year_built: zod.number().nullish(),
          yacht_type: zod.string().nullish(),
          length_meters: zod.number().nullish(),
          beam_meters: zod.number().nullish(),
          cabins: zod.number().nullish(),
          guests: zod.number().nullish(),
          crew: zod.number().nullish(),
          engine_hours: zod.number().nullish(),
          marina_location: zod.string().nullish(),
          flag: zod.string().nullish(),
          commercial_registration: zod.boolean().nullish(),
        })
        .describe(
          "Passport-only snapshot of a yacht for an ROI calculation that is NOT backed by a saved My-Yacht profile (manual entry). Carries identity and dimensions only — purchase price, crew, expenses and financing are supplied separately via `overrides`. A manual ROI yacht is persisted ONLY in ROI history (roi_calculations.yacht_snapshot) and never creates a row in the yachts table.",
        ),
      zod.null(),
    ])
    .optional()
    .describe(
      "Passport snapshot for a manually-entered yacht (no saved profile). Provide EITHER yacht_id OR yacht_snapshot. Persisted only in ROI history; never creates a yachts row.",
    ),
  region: zod.enum([
    "mediterranean",
    "caribbean",
    "northern_europe",
    "asia_pacific_me",
    "middle_east",
  ]),
  occupancy_target: zod
    .union([zod.enum(["conservative", "realistic", "optimistic"]), zod.null()])
    .optional()
    .describe("Hint for AI mode; ignored in manual modes"),
  pricing_mode: zod
    .enum(["manual_daily", "manual_weekly", "ai"])
    .describe(
      "How the charter rate is determined:\n\* manual_daily  — user provides daily rate + number of charter days\n\* manual_weekly — user provides weekly rate + number of charter weeks\n\* ai            — engine asks AI (web-search) for plausible rate + weeks\n",
    ),
  manual_rate_eur: zod
    .number()
    .min(calculateRoiBodyManualRateEurMin)
    .nullish()
    .describe("Per-day rate for manual_daily, per-week rate for manual_weekly"),
  manual_charter_units: zod
    .number()
    .min(calculateRoiBodyManualCharterUnitsMin)
    .max(calculateRoiBodyManualCharterUnitsMax)
    .nullish()
    .describe(
      "Number of charter days OR weeks per year, matching pricing_mode",
    ),
  management_fee_pct: zod
    .number()
    .min(calculateRoiBodyManagementFeePctMin)
    .max(calculateRoiBodyManagementFeePctMax)
    .nullish()
    .describe(
      "Optional management-fee percentage override. null = use the owner's manual monthly management fee on the yacht, or none if unset.",
    ),
  target_weeks: zod
    .number()
    .min(calculateRoiBodyTargetWeeksMin)
    .max(calculateRoiBodyTargetWeeksMax)
    .nullish()
    .describe("AI mode only — override AI-predicted charter weeks"),
  charter_type: zod
    .union([
      zod
        .enum(["weekly", "daily"])
        .describe(
          "AI mode only. Whether the yacht is chartered by the week or by the day.\nOnly consulted for regions that model a daily-charter market (e.g.\nCaribbean offers both; Middle East \/ Dubai is daily-only). Ignored for\nregions without a daily model and for manual pricing modes.\n",
        ),
      zod.null(),
    ])
    .optional()
    .describe(
      "AI mode only. weekly | daily. Only consulted for regions with a daily-charter model (Caribbean = both, Middle East = daily-only); ignored elsewhere and for manual modes. Defaults to the region's primary basis when null.",
    ),
  overrides: zod
    .union([
      zod
        .object({
          crew_breakdown: zod
            .array(
              zod.object({
                role: zod
                  .string()
                  .describe(
                    'Free-text role label (e.g. \"Captain\", \"Chef\")',
                  ),
                monthly_salary_eur: zod
                  .number()
                  .min(
                    calculateRoiBodyOverridesOneCrewBreakdownItemMonthlySalaryEurMin,
                  ),
                months_per_year: zod
                  .number()
                  .min(1)
                  .max(
                    calculateRoiBodyOverridesOneCrewBreakdownItemMonthsPerYearMax,
                  ),
              }),
            )
            .nullish(),
          purchase_price_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOnePurchasePriceEurMin)
            .nullish()
            .describe(
              "Yacht purchase price for THIS calculation (capital base for ROI \/ payback \/ depreciation). Lives only in ROI — entered on the scenario screen, prefilled from a saved yacht when present, never written back.",
            ),
          monthly_crew_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyCrewEurMin)
            .nullish(),
          monthly_mooring_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyMooringEurMin)
            .nullish(),
          monthly_fuel_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyFuelEurMin)
            .nullish(),
          monthly_provisioning_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyProvisioningEurMin)
            .nullish(),
          monthly_communications_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyCommunicationsEurMin)
            .nullish(),
          monthly_maintenance_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyMaintenanceEurMin)
            .nullish(),
          monthly_management_fee_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyManagementFeeEurMin)
            .nullish(),
          monthly_misc_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneMonthlyMiscEurMin)
            .nullish(),
          annual_insurance_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneAnnualInsuranceEurMin)
            .nullish(),
          annual_registration_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneAnnualRegistrationEurMin)
            .nullish(),
          annual_classification_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneAnnualClassificationEurMin)
            .nullish(),
          annual_antifouling_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneAnnualAntifoulingEurMin)
            .nullish(),
          annual_refit_reserve_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneAnnualRefitReserveEurMin)
            .nullish(),
          charter_commission_pct: zod
            .number()
            .min(calculateRoiBodyOverridesOneCharterCommissionPctMin)
            .max(calculateRoiBodyOverridesOneCharterCommissionPctMax)
            .nullish(),
          financing_type: zod
            .union([zod.enum(["cash", "loan"]), zod.null()])
            .optional(),
          loan_amount_eur: zod
            .number()
            .min(calculateRoiBodyOverridesOneLoanAmountEurMin)
            .nullish(),
          loan_rate_pct: zod
            .number()
            .min(calculateRoiBodyOverridesOneLoanRatePctMin)
            .nullish(),
          loan_term_years: zod
            .number()
            .min(calculateRoiBodyOverridesOneLoanTermYearsMin)
            .nullish(),
        })
        .describe(
          "Optional overrides for the ROI calculation. crew_breakdown is stored for history\/re-open; the engine uses monthly_crew_eur as the crew total.",
        ),
      zod.null(),
    ])
    .optional()
    .describe(
      'Per-calculation crew\/expense\/financing overrides. Applied on top of the saved yacht for THIS calculation only and never written back to the yacht profile. A null field falls back to the saved yacht value; if that is also empty the engine omits the line (maintenance, management fee and broker commission always use a default). Choosing financing_type \"cash\" clears any inherited loan figures for the calc.',
    ),
});

export const calculateRoiResponseRiskScoreMax = 10;

